import{M as e,d as t,h as n}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as r}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var i=JSON.parse(`{"title":"SSR Using ModuleRunner API","description":"","frontmatter":{},"headers":[],"relativePath":"changes/ssr-using-modulerunner.md","filePath":"changes/ssr-using-modulerunner.md"}`),a={name:`changes/ssr-using-modulerunner.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /changes\\ssr-using-modulerunner.md for this page in Markdown format</div><h1 id="ssr-using-modulerunner-api" tabindex="-1">SSR Using <code>ModuleRunner</code> API <a class="header-anchor" href="#ssr-using-modulerunner-api" aria-label="Permalink to “SSR Using ModuleRunner API”">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Feedback</p><p>Give us feedback at <a href="https://github.com/vitejs/vite/discussions/16358" target="_blank" rel="noreferrer">Environment API feedback discussion</a></p></div><p><code>server.ssrLoadModule</code> has been replaced by importing from a <a href="/guide/api-environment#modulerunner">Module Runner</a>.</p><p>Affected scope: <code>Vite Plugin Authors</code></p><div class="warning custom-block"><p class="custom-block-title">Future Deprecation</p><p><code>ModuleRunner</code> was first introduced in <code>v6.0</code>. The deprecation of <code>server.ssrLoadModule</code> is planned for a future major. To identify your usage, set <code>future.removeSsrLoadModule</code> to <code>&quot;warn&quot;</code> in your vite config.</p></div><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to “Motivation”">​</a></h2><p>The\xA0<code>server.ssrLoadModule(url)</code>\xA0only allows importing modules in the\xA0<code>ssr</code>\xA0environment and can only execute the modules in the same process as the Vite dev server. For apps with custom environments, each is associated with a\xA0<code>ModuleRunner</code>\xA0that may be running in a separate thread or process. To import modules, we now have\xA0<code>moduleRunner.import(url)</code>.</p><h2 id="migration-guide" tabindex="-1">Migration Guide <a class="header-anchor" href="#migration-guide" aria-label="Permalink to “Migration Guide”">​</a></h2><p>Check out the <a href="./../guide/api-environment-frameworks">Environment API for Frameworks Guide</a>.</p><p><code>server.ssrFixStacktrace</code> and <code>server.ssrRewriteStacktrace</code> do not have to be called when using the Module Runner APIs. The stack traces will be updated unless <code>sourcemapInterceptor</code> is set to <code>false</code>.</p>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};